package main

import "fmt"

// Struct (like a class without inheritance)
type User struct {
    ID    int
    Name  string
    Email string
    Age   int
}

// Method on struct (value receiver)
func (u User) Greet() string {
    return fmt.Sprintf("Hi, I'm %s (%d)", u.Name, u.Age)
}

// Method with pointer receiver (can modify)
func (u *User) Birthday() {
    u.Age++
}

// Function with multiple return values
func Divide(a, b float64) (float64, error) {
    if b == 0 {
        return 0, fmt.Errorf("division by zero")
    }
    return a / b, nil
}

// Named return values
func Swap(x, y int) (a int, b int) {
    a = y
    b = x
    return // naked return
}

func main() {
    // Variable declarations
    var name string = "Go"
    version := 1.22  // Short declaration (type inferred)
    fmt.Printf("%s v%.1f\n", name, version)

    // Struct initialization
    user := User{ID: 1, Name: "Alice", Email: "alice@example.com", Age: 25}
    fmt.Println(user.Greet())

    user.Birthday()
    fmt.Printf("Now %d years old\n", user.Age)

    // Multiple return values
    result, err := Divide(10, 3)
    if err != nil {
        fmt.Println("Error:", err)
    } else {
        fmt.Printf("10 / 3 = %.2f\n", result)
    }

    // Zero values
    var empty User  // {0, "", "", 0}
    fmt.Printf("Zero user: %+v\n", empty)

    // Maps
    scores := map[string]int{"Alice": 95, "Bob": 87}
    scores["Charlie"] = 91
    delete(scores, "Bob")
    for name, score := range scores {
        fmt.Printf("%s: %d\n", name, score)
    }
}
