package main

import (
    "fmt"
    "math/rand"
    "sync"
    "time"
)

// Producer-consumer with channels
func producer(id int, ch chan<- int, wg *sync.WaitGroup) {
    defer wg.Done()
    for i := 0; i < 5; i++ {
        value := id*100 + i
        ch <- value
        fmt.Printf("Producer %d sent: %d\n", id, value)
        time.Sleep(time.Duration(rand.Intn(500)) * time.Millisecond)
    }
}

func consumer(id int, ch <-chan int, done chan<- bool) {
    for value := range ch {
        fmt.Printf("Consumer %d received: %d\n", id, value)
        time.Sleep(time.Duration(rand.Intn(300)) * time.Millisecond)
    }
    done <- true
}

// Fan-out, fan-in pattern
func generateNumbers(count int) <-chan int {
    ch := make(chan int)
    go func() {
        defer close(ch)
        for i := 1; i <= count; i++ {
            ch <- i
        }
    }()
    return ch
}

func square(in <-chan int) <-chan int {
    out := make(chan int)
    go func() {
        defer close(out)
        for n := range in {
            out <- n * n
        }
    }()
    return out
}

func merge(channels ...<-chan int) <-chan int {
    var wg sync.WaitGroup
    merged := make(chan int)

    for _, ch := range channels {
        wg.Add(1)
        go func(c <-chan int) {
            defer wg.Done()
            for val := range c {
                merged <- val
            }
        }(ch)
    }

    go func() {
        wg.Wait()
        close(merged)
    }()
    return merged
}

func main() {
    // Producer-consumer
    ch := make(chan int, 10)  // Buffered channel
    var wg sync.WaitGroup

    for i := 1; i <= 3; i++ {
        wg.Add(1)
        go producer(i, ch, &wg)
    }

    done := make(chan bool, 2)
    go consumer(1, ch, done)
    go consumer(2, ch, done)

    wg.Wait()
    close(ch)
    <-done
    <-done

    // Fan-out, fan-in
    source := generateNumbers(10)
    sq1 := square(source)
    sq2 := square(source)

    for result := range merge(sq1, sq2) {
        fmt.Printf("Squared: %d\n", result)
    }
}
