package main

import (
    "fmt"
    "math"
)

// Interfaces
type Shape interface {
    Area() float64
    Perimeter() float64
    String() string
}

type Scalable interface {
    Scale(factor float64)
}

// Structs
type Circle struct {
    Radius float64
}

func (c Circle) Area() float64      { return math.Pi * c.Radius * c.Radius }
func (c Circle) Perimeter() float64  { return 2 * math.Pi * c.Radius }
func (c Circle) String() string      { return fmt.Sprintf("Circle(r=%.1f)", c.Radius) }
func (c *Circle) Scale(factor float64) { c.Radius *= factor }

type Rectangle struct {
    Width, Height float64
}

func (r Rectangle) Area() float64      { return r.Width * r.Height }
func (r Rectangle) Perimeter() float64  { return 2 * (r.Width + r.Height) }
func (r Rectangle) String() string      { return fmt.Sprintf("Rect(%.1fx%.1f)", r.Width, r.Height) }
func (r *Rectangle) Scale(factor float64) {
    r.Width *= factor
    r.Height *= factor
}

// Composition via embedding
type NamedShape struct {
    Shape  // Embedded interface
    Name   string
    Color  string
}

func (ns NamedShape) Describe() string {
    return fmt.Sprintf("%s %s (%s) - Area: %.2f",
        ns.Color, ns.Name, ns.Shape.String(), ns.Shape.Area())
}

// Function accepting interface
func PrintShapeInfo(s Shape) {
    fmt.Printf("%s -> Area: %.2f, Perimeter: %.2f\n",
        s.String(), s.Area(), s.Perimeter())
}

// Type assertion
func ScaleIfPossible(s Shape, factor float64) {
    if scalable, ok := s.(Scalable); ok {
        scalable.Scale(factor)
        fmt.Printf("Scaled by %.1f: %s\n", factor, s.String())
    } else {
        fmt.Printf("%s cannot be scaled\n", s.String())
    }
}

func main() {
    shapes := []Shape{
        Circle{Radius: 5},
        Rectangle{Width: 4, Height: 6},
        Circle{Radius: 3},
    }

    for _, s := range shapes {
        PrintShapeInfo(s)
    }

    // Embedding
    ns := NamedShape{
        Shape: Circle{Radius: 10},
        Name:  "Big Circle",
        Color: "Red",
    }
    fmt.Println(ns.Describe())

    // Type assertion
    c := Circle{Radius: 5}
    ScaleIfPossible(&c, 2.0)

    // Type switch
    for _, s := range shapes {
        switch v := s.(type) {
        case Circle:
            fmt.Printf("Circle with radius %.1f\n", v.Radius)
        case Rectangle:
            fmt.Printf("Rectangle %0.1fx%.1f\n", v.Width, v.Height)
        }
    }
}
