package main

import (
    "errors"
    "fmt"
    "strconv"
)

// Sentinel errors
var (
    ErrNotFound     = errors.New("not found")
    ErrUnauthorized = errors.New("unauthorized")
    ErrValidation   = errors.New("validation failed")
)

// Custom error type
type ValidationError struct {
    Field   string
    Message string
}

func (e *ValidationError) Error() string {
    return fmt.Sprintf("validation error: %s - %s", e.Field, e.Message)
}

// Custom error with wrapping
type HTTPError struct {
    StatusCode int
    Message    string
    Err        error
}

func (e *HTTPError) Error() string {
    return fmt.Sprintf("HTTP %d: %s", e.StatusCode, e.Message)
}

func (e *HTTPError) Unwrap() error {
    return e.Err
}

// Function returning error
func FindUser(id string) (*User, error) {
    if id == "" {
        return nil, &ValidationError{Field: "id", Message: "cannot be empty"}
    }

    numID, err := strconv.Atoi(id)
    if err != nil {
        return nil, fmt.Errorf("invalid user ID '%s': %w", id, ErrValidation)
    }

    users := map[int]*User{
        1: {ID: 1, Name: "Alice"},
        2: {ID: 2, Name: "Bob"},
    }

    user, exists := users[numID]
    if !exists {
        return nil, fmt.Errorf("user %d: %w", numID, ErrNotFound)
    }
    return user, nil
}

// Idiomatic error handling pattern
func GetUserHandler(id string) {
    user, err := FindUser(id)
    if err != nil {
        // errors.Is checks the error chain
        if errors.Is(err, ErrNotFound) {
            fmt.Println("User not found, show 404")
            return
        }
        if errors.Is(err, ErrValidation) {
            // errors.As extracts typed error
            var validationErr *ValidationError
            if errors.As(err, &validationErr) {
                fmt.Printf("Field '%s': %s\n", validationErr.Field, validationErr.Message)
            }
            return
        }
        fmt.Println("Unknown error:", err)
        return
    }
    fmt.Printf("Found user: %s\n", user.Name)
}

type User struct {
    ID   int
    Name string
}

func main() {
    GetUserHandler("1")    // Found user: Alice
    GetUserHandler("99")   // User not found, show 404
    GetUserHandler("abc")  // validation error
    GetUserHandler("")     // Field 'id': cannot be empty
}
