package main

import (
    "encoding/json"
    "fmt"
    "log"
    "net/http"
    "strconv"
    "strings"
    "sync"
    "time"
)

type User struct {
    ID    int    `json:"id"`
    Name  string `json:"name"`
    Email string `json:"email"`
}

type UserStore struct {
    mu     sync.RWMutex
    users  map[int]User
    nextID int
}

func NewUserStore() *UserStore {
    return &UserStore{
        users: map[int]User{
            1: {ID: 1, Name: "Alice", Email: "alice@example.com"},
            2: {ID: 2, Name: "Bob", Email: "bob@example.com"},
        },
        nextID: 3,
    }
}

func (s *UserStore) GetAll() []User {
    s.mu.RLock()
    defer s.mu.RUnlock()
    users := make([]User, 0, len(s.users))
    for _, u := range s.users {
        users = append(users, u)
    }
    return users
}

func (s *UserStore) GetByID(id int) (User, bool) {
    s.mu.RLock()
    defer s.mu.RUnlock()
    u, ok := s.users[id]
    return u, ok
}

func (s *UserStore) Create(name, email string) User {
    s.mu.Lock()
    defer s.mu.Unlock()
    user := User{ID: s.nextID, Name: name, Email: email}
    s.users[user.ID] = user
    s.nextID++
    return user
}

// Middleware
func LoggingMiddleware(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        start := time.Now()
        next.ServeHTTP(w, r)
        log.Printf("%s %s %s", r.Method, r.URL.Path, time.Since(start))
    })
}

func JSONMiddleware(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        w.Header().Set("Content-Type", "application/json")
        next.ServeHTTP(w, r)
    })
}

func main() {
    store := NewUserStore()
    mux := http.NewServeMux()

    // GET /users
    mux.HandleFunc("GET /users", func(w http.ResponseWriter, r *http.Request) {
        json.NewEncoder(w).Encode(store.GetAll())
    })

    // GET /users/{id}
    mux.HandleFunc("GET /users/{id}", func(w http.ResponseWriter, r *http.Request) {
        id, err := strconv.Atoi(r.PathValue("id"))
        if err != nil {
            http.Error(w, `{"error":"invalid id"}`, http.StatusBadRequest)
            return
        }
        user, found := store.GetByID(id)
        if !found {
            http.Error(w, `{"error":"not found"}`, http.StatusNotFound)
            return
        }
        json.NewEncoder(w).Encode(user)
    })

    // POST /users
    mux.HandleFunc("POST /users", func(w http.ResponseWriter, r *http.Request) {
        var req struct {
            Name  string `json:"name"`
            Email string `json:"email"`
        }
        if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
            http.Error(w, `{"error":"invalid json"}`, http.StatusBadRequest)
            return
        }
        if req.Name == "" || req.Email == "" {
            http.Error(w, `{"error":"name and email required"}`, http.StatusBadRequest)
            return
        }
        user := store.Create(req.Name, req.Email)
        w.WriteHeader(http.StatusCreated)
        json.NewEncoder(w).Encode(user)
    })

    // Chain middleware
    handler := LoggingMiddleware(JSONMiddleware(mux))

    fmt.Println("Server running on :8080")
    log.Fatal(http.ListenAndServe(":8080", handler))
}
