// mathutil.go
package mathutil

import "errors"

var ErrNegativeInput = errors.New("negative input not allowed")

func Fibonacci(n int) (int, error) {
    if n < 0 {
        return 0, ErrNegativeInput
    }
    if n <= 1 {
        return n, nil
    }
    a, b := 0, 1
    for i := 2; i <= n; i++ {
        a, b = b, a+b
    }
    return b, nil
}

func IsPrime(n int) bool {
    if n < 2 {
        return false
    }
    for i := 2; i*i <= n; i++ {
        if n%i == 0 {
            return false
        }
    }
    return true
}
